INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-cf446b4c-moex-00244', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '關於添附之敘述，下列何者錯誤？', '["加工於他人之動產者，其加工物之所有權屬於加工人。但因材料之價值顯逾加工所增之價值者， 其加工物之所有權屬於材料所有人", "動產與他人之動產附合，非毀損不能分離或分離需費過鉅者，若無其他條件，各動產所有人按 其動產附合時之價值，共有合成物", "動產與他人之動產混合，不能識別或識別需費過鉅者，若無其他條件，各動產所有人按其動產 混合時之價值，共有混合物", "動產因附合而為不動產之重要成分者，不動產所有權人取得動產所有權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00245', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲、乙、丙三人分別共有A地，應有部分各三分之一，並經登記於土地登記簿。甲以其應有部分 設定普通抵押權於丁。丙請求分割A地。下列敘述何者錯誤？', '["丁同意A地之分割者，其抵押權移存於甲因分割而分得之部分", "丁經通知A地分割者，其抵押權移存於甲因分割而分得之部分", "丁經共有人告知訴訟而未參加者，其抵押權移存於甲因分割而分得之部分", "丁已參加共有物分割訴訟，其抵押權移存於甲因分割而分得之部分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00246', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲經營健身房，因疫情致財務陷於困境，故以其母留下之多條珍珠項鍊作為擔保品，向乙借款。 下列敘述何者錯誤？', '["乙讓與該債權於第三人，該動產質權亦隨之移轉", "乙死亡，其繼承人取得該動產質權", "甲乙間得以占有改定方式設質於乙", "該動產質權之擔保範圍，包含原債權及利息"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00247', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲駕駛愛車至乙洗車場洗車，洗車機正常運作係以輸送帶之滾筒帶動車輛前輪進入洗車機，惟甲 之車輛於洗車過程中操作致脫軌受損。下列敘述何者正確？', '["洗車場屬於民法第191條之3危險活動責任", "依軌道行駛之動力車輛，不適用民法侵權行為之賠償規定", "若甲未遵循洗車場之指示，致車輛以自身動力脫離直線軌道，應自負其責", "依民法規定，乙洗車場應負無過失責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00248', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲於購物網站購買一台吸塵器，並於網路上付清全額貨款。該購物網站將吸塵器寄送至甲所住之 大樓，由大樓管理員代為簽收。此行為屬於下列何種交付？', '["現實交付", "簡易交付", "占有改定", "指示交付"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00249', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲已離婚，有一子乙。嗣後，甲與丙女結婚，乙與丁女結婚。丙女與丁女關係為何？', '["無親屬關係", "一親等直系姻親", "一親等直系血親", "二親等直系姻親"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00250', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲、乙之婚姻被法院判決無效確定。甲乙現存婚後財產之價值計算，以何時為準？', '["結婚登記時", "起訴時", "判決確定時", "法定財產制關係消滅時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00251', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲女現年17歲，年幼時父母雙亡，由同居之祖母乙任監護人。乙之下列何種行為，須經法院許可？', '["乙為了籌措甲之生活費，代理甲將甲名義之股票賣出", "乙代理甲將甲名義之不動產贈與甲之叔叔丙", "甲欲與丁男結婚，經乙之同意", "甲遭遇車禍昏迷，乙趕到醫院簽署手術同意書"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00252', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲死亡時，留有動產價值新臺幣（下同）240萬元，甲尚有對乙債務250萬元未清償，僅有兄弟 丙丁二人為其繼承人。下列敘述何者正確？', '["丙依法拋棄繼承後，未以書面通知丁，丙之拋棄無效", "丁僅繼承債務125萬元", "丙隱匿甲所留動產之一半，得以120萬元為限負清償責任", "對乙清償250萬元後，丙丁不得以超出所得遺產為由，請求乙返還10萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00253', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '關於遺產分割之實行，下列何者正確？', '["遺產分割後，其未清償之被繼承人債務，移歸一定之人承受，雖經債權人同意，各繼承人仍不 免除連帶責任", "繼承人連帶責任，自遺產分割時起，如債權清償期在遺產分割後者，自清償期屆滿時起，經過 10年而免除", "乙父於生前贈與新臺幣（下同）100 萬元予其子甲作為創業資金，於乙死亡進行遺產分割時， 應由甲之應繼分內扣還", "乙父於生前贈與 10 萬元給其子甲當補習費用，乙死亡後，應將該贈與價額加入繼承開始時被 繼承人乙所有之財產中，為應繼遺產"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
